const body = $input.first().json.body || $input.first().json;

const user_id = body.user_id || null;
if (!user_id) throw new Error('Missing required field: user_id');

// Accept optional pre-passed fields to avoid extra DB calls
const email         = body.email         || null;
const business_name = body.business_name || null;
const operator_name = body.operator_name || null;
const plan_tier     = body.plan_tier     || null;
const active_tools  = Array.isArray(body.active_tools) ? body.active_tools : null;
const dashboard_url = body.dashboard_url || null;

const has_context = !!(email && operator_name);

return [{
  json: {
    user_id,
    has_context,
    prefilled: { email, business_name, operator_name, plan_tier, active_tools, dashboard_url },
    now: new Date().toISOString()
  }
}];

const items = $input.all();
const origin = $('Parse & Validate').first().json;

if (!items || items.length < 2) {
  throw new Error(`Expected 2 fetch results, got ${items?.length || 0}`);
}

const profileRaw = items[0].json;
const aiRaw      = items[1].json;

const profile  = Array.isArray(profileRaw) ? profileRaw[0] : profileRaw;
const aiConfig = Array.isArray(aiRaw)      ? aiRaw[0]      : aiRaw;

if (!profile?.user_id) throw new Error(`No user_profiles record for user_id: ${origin.user_id}`);

// Tool metadata
const toolMeta = {
  launchpad_tool_1:  { name: 'AI Lead Finder',       emoji: '🎯', action: 'Find your first 50 qualified prospects' },
  launchpad_tool_2:  { name: 'Copy Generator',        emoji: '✍️', action: 'Generate homepage and offer copy'       },
  launchpad_tool_3:  { name: 'Offer Builder',         emoji: '🔥', action: 'Structure your core offer'              },
  launchpad_tool_4:  { name: 'Email Sequencer',       emoji: '📧', action: 'Build a 5-step nurture sequence'        },
  launchpad_tool_5:  { name: 'Funnel Mapper',         emoji: '🗺️', action: 'Map your end-to-end sales funnel'       },
  launchpad_tool_6:  { name: 'Competitor Analyst',    emoji: '🔍', action: 'Analyse your top 3 competitors'         },
  launchpad_tool_7:  { name: 'Ad Creative Studio',    emoji: '🎨', action: 'Create 5 ad concepts in 10 minutes'     },
  launchpad_tool_8:  { name: 'VSL Script Writer',     emoji: '🎬', action: 'Write a 5-minute video sales letter'    },
  launchpad_tool_9:  { name: 'AI Sales Closer',       emoji: '💰', action: 'Script your close and handle objections'},
  launchpad_tool_10: { name: 'Business Automator',    emoji: '⚡', action: 'Automate your top 3 manual tasks'       }
};

const recommended = Array.isArray(aiConfig?.recommended_tools) ? aiConfig.recommended_tools : ['launchpad_tool_2', 'launchpad_tool_1'];
const top3        = recommended.slice(0, 3);
const top3Meta    = top3.map(id => ({ id, ...(toolMeta[id] || { name: id, emoji: '🛠', action: 'Get started' }) }));
const primaryTool = top3Meta[0];

// Name resolution
const first_name    = profile.first_name || (profile.business_name || 'there').split(' ')[0];
const business_name = profile.business_name || origin.prefilled.business_name || 'Your Business';
const email         = profile.email || origin.prefilled.email;
const plan_tier     = (profile.plan_tier || origin.prefilled.plan_tier || 'free').toLowerCase();
const operator_name = aiConfig?.operator_name || origin.prefilled.operator_name || `${business_name} AI Operator`;
const operator_tone = aiConfig?.operator_tone || 'professional';
const primary_niche = aiConfig?.primary_niche || 'Business Automation';
const gtm_summary   = aiConfig?.gtm_strategy_summary || null;

if (!email) throw new Error(`No email found for user_id: ${origin.user_id}`);

const planLabels = { free: 'Free', starter: 'Starter', pro: 'Pro', scale: 'Scale' };
const app_base   = process.env.APP_BASE_URL || 'https://app.nova-ops.space';
const dashboard_url = origin.prefilled.dashboard_url || `${app_base}/dashboard/${origin.user_id}`;

const upgradeCTAs = {
  free:    { cta: 'Upgrade to Starter for 100 credits and 5 Launchpad tools', link: 'https://nova-ops.space/upgrade/starter' },
  starter: { cta: 'Upgrade to Pro for 500 credits and full Nova OS',           link: 'https://nova-ops.space/upgrade/pro'     },
  pro:     { cta: 'Upgrade to Scale for unlimited credits and team seats',      link: 'https://nova-ops.space/upgrade/scale'   },
  scale:   { cta: null, link: null }
};
const upgrade = upgradeCTAs[plan_tier] || upgradeCTAs['free'];

return [{
  json: {
    user_id:      origin.user_id,
    now:          origin.now,
    email,
    first_name,
    business_name,
    plan_tier,
    plan_label:   planLabels[plan_tier] || 'Free',
    operator_name,
    operator_tone,
    primary_niche,
    gtm_summary,
    top3_tools:   top3Meta,
    primary_tool: primaryTool,
    dashboard_url,
    upgrade_cta:  upgrade.cta,
    upgrade_link: upgrade.link
  }
}];

const d = $input.first().json;

const tool1 = d.top3_tools[0] || { emoji: '🛠', name: 'Launchpad Tool', action: 'Get started' };
const tool2 = d.top3_tools[1] || null;
const tool3 = d.top3_tools[2] || null;

const toolListHtml = d.top3_tools.map((t, i) => `
  <div style="display:flex;align-items:flex-start;gap:12px;padding:14px;background:#f8fafc;border-radius:8px;margin-bottom:8px">
    <span style="font-size:24px;line-height:1">${t.emoji}</span>
    <div>
      <p style="margin:0;font-weight:600;color:#1e293b">${t.name}</p>
      <p style="margin:4px 0 0;font-size:13px;color:#64748b">${t.action}</p>
    </div>
  </div>`).join('');

const gtmBlock = d.gtm_summary ? `
  <div style="background:#f0fdf4;border-left:4px solid #22c55e;padding:16px;border-radius:0 8px 8px 0;margin:20px 0">
    <p style="margin:0 0 4px;font-size:12px;font-weight:600;color:#166534;text-transform:uppercase;letter-spacing:0.05em">Your GTM Strategy</p>
    <p style="margin:0;color:#15803d;font-size:14px">${d.gtm_summary}</p>
  </div>` : '';

const upgradeBlock = d.upgrade_cta ? `
  <div style="background:#fefce8;border:1px solid #fde68a;border-radius:8px;padding:16px;margin-top:24px">
    <p style="margin:0;font-size:14px;color:#92400e">💡 <strong>Ready to unlock more?</strong> ${d.upgrade_cta} — <a href="${d.upgrade_link}" style="color:#6366f1;font-weight:600">Upgrade now →</a></p>
  </div>` : '';

const emailHtml = `
<div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:600px;margin:0 auto;color:#1a1a1a">
  <div style="background:linear-gradient(135deg,#6366f1 0%,#8b5cf6 100%);padding:36px 40px;border-radius:16px 16px 0 0">
    <p style="color:rgba(255,255,255,0.7);margin:0;font-size:12px;letter-spacing:0.08em;text-transform:uppercase">Nova OPS</p>
    <h1 style="color:white;margin:8px 0 0;font-size:26px;font-weight:700;line-height:1.3">Welcome, ${d.first_name} —<br>your workspace is live.</h1>
  </div>

  <div style="background:#ffffff;padding:40px;border:1px solid #e2e8f0;border-top:none;border-radius:0 0 16px 16px">

    <p style="font-size:16px;color:#334155;line-height:1.7">Your AI operator, <strong>${d.operator_name}</strong>, has been configured for <strong>${d.business_name}</strong> in the <strong>${d.primary_niche}</strong> space.</p>

    ${gtmBlock}

    <h2 style="font-size:16px;font-weight:700;color:#0f172a;margin:28px 0 12px">Your top 3 Launchpad tools:</h2>
    ${toolListHtml}

    <div style="background:#6366f1;border-radius:10px;padding:24px;margin:28px 0;text-align:center">
      <p style="color:rgba(255,255,255,0.8);margin:0 0 6px;font-size:13px">Start here →</p>
      <p style="color:white;font-size:18px;font-weight:700;margin:0 0 20px">${tool1.emoji} ${tool1.name}</p>
      <a href="${d.dashboard_url}" style="display:inline-block;padding:12px 32px;background:white;color:#6366f1;border-radius:8px;text-decoration:none;font-weight:700;font-size:15px">Open Your Workspace →</a>
    </div>

    ${upgradeBlock}

    <hr style="border:none;border-top:1px solid #e2e8f0;margin:32px 0">
    <p style="font-size:13px;color:#64748b;line-height:1.6">You're on the <strong>${d.plan_label}</strong> plan. Questions? Just reply to this email — our team in Tampa, FL responds fast.</p>
    <p style="font-size:12px;color:#94a3b8">Nova OPS · Tampa, FL · <a href="https://nova-ops.space" style="color:#94a3b8">nova-ops.space</a></p>
  </div>
</div>`.trim();

const toolListText = d.top3_tools.map(t => `${t.emoji} ${t.name} — ${t.action}`).join('\n');

const emailText = `Welcome to Nova OPS, ${d.first_name}!

Your AI operator "${d.operator_name}" is live for ${d.business_name}.
${d.gtm_summary ? `\nYour GTM strategy: ${d.gtm_summary}` : ''}

Your top 3 Launchpad tools:
${toolListText}

Start with ${tool1.emoji} ${tool1.name}: ${tool1.action}

Open your workspace: ${d.dashboard_url}
${d.upgrade_cta ? `\nReady for more? ${d.upgrade_cta}: ${d.upgrade_link}` : ''}

Questions? Reply to this email.
Nova OPS · support@nova-ops.space`;

return [{
  json: {
    ...d,
    email_subject: `Welcome to Nova OPS, ${d.first_name} — your ${d.operator_name} is ready`,
    email_html:    emailHtml,
    email_text:    emailText,
    notification_message: `Your AI operator ${d.operator_name} is configured and ready. Start with ${tool1.emoji} ${tool1.name}: ${tool1.action}.`
  }
}];

const items = $input.all();
const origin = $('Build Email + Notification Content').first().json;

if (!items || items.length < 2) {
  throw new Error(`Expected 2 results (email send + notification insert), got ${items?.length || 0}`);
}

const emailResult = items[0].json;
const notifResult = items[1].json;

const email_id      = emailResult?.id   || null;
const email_sent    = !!email_id;
const notif_record  = Array.isArray(notifResult) ? notifResult[0] : notifResult;
const notif_id      = notif_record?.id  || null;
const notif_created = !!notif_id;

if (!email_sent)    console.warn(`Welcome email may have failed for ${origin.email}. Response: ${JSON.stringify(emailResult)}`);
if (!notif_created) console.warn(`Notification insert may have failed for user ${origin.user_id}. Response: ${JSON.stringify(notifResult)}`);

return [{
  json: {
    ...origin,
    email_sent,
    email_id,
    notif_created,
    notif_id
  }
}];
